// BTSlider barrel — exports public API only.
export 'slider.types.dart';
export 'slider.widget.dart';

// BTSlider types — Figma source: node 434:7617.
// Figma thumb: node 434:7227 — 24 px diameter, 2.5 px white border.

/// Layout and thumb count for [BTSlider].
enum BTSliderType {
  /// Horizontal slider with a single thumb.
  defaults,

  /// Horizontal slider with two thumbs (start + end).
  range,

  /// Vertical slider with a single thumb.
  vertical,
}

/// Color variant for the active track and thumb (Figma 434:7227).
enum BTSliderVariant {
  /// icon.primary (#292f37). Resolved from theme tokens at render time.
  defaults,

  /// icon.error (#991515).
  error,
}

// BTSlider — interactive range slider atom (Figma 434:7617).
//
// Three layout types: defaults (horizontal · 1 thumb), range
// (horizontal · 2 thumbs), vertical (1 thumb rotated).
// Two color variants: defaults (icon.primary) · error (icon.error).
// Disabled state is controlled by the [isEnabled] prop.
//
// Example:
// ```dart
// // Default horizontal slider
// BTSlider(value: 50, onValueChanged: (v) => setState(() => _val = v))
//
// // Range slider
// BTSlider.range(
//   startValue: 20, endValue: 80,
//   onStartChanged: (v) => setState(() => _start = v),
//   onEndChanged:   (v) => setState(() => _end   = v),
// )
//
// // Vertical error slider
// BTSlider.vertical(
//   variant: BTSliderVariant.error,
//   value: 60,
//   onValueChanged: (v) => setState(() => _level = v),
// )
// ```

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/slider/slider.types.dart';
import 'package:flutter/material.dart';

// Component-specific palette.
// Both variants resolve from context.btColor at render time
// (handled in [_BTSliderState._activeColor]) so they track theme
// switches (light/dark) and tenant overrides.

// ── Custom thumb shapes (Figma: 24 px diameter, 2.5 px white border, shadow) ─

// Thumb radius — 24 px diameter (Figma 434:7227), 2.5 px white border.
const _kThumbRadius = 12.0;
const _kBorderWidth = 2.5;

/// Single-thumb custom shape: border (border.primary) + thumb fill + drop shadow.
class _BTThumbShape extends SliderComponentShape {
  const _BTThumbShape({required this.borderColor});

  final Color borderColor;

  @override
  Size getPreferredSize(bool isEnabled, bool isDiscrete) =>
      const Size.fromRadius(_kThumbRadius);

  @override
  void paint(
    PaintingContext context,
    Offset center, {
    required Animation<double> activationAnimation,
    required Animation<double> enableAnimation,
    required bool isDiscrete,
    required TextPainter labelPainter,
    required RenderBox parentBox,
    required SliderThemeData sliderTheme,
    required TextDirection textDirection,
    required double value,
    required double textScaleFactor,
    required Size sizeWithOverflow,
  }) {
    final canvas = context.canvas;
    final fill = Paint()
      ..color = sliderTheme.thumbColor ?? const Color(0xFF000000);

    canvas
      ..drawCircle(center, _kThumbRadius, Paint()..color = borderColor)
      ..drawCircle(center, _kThumbRadius - _kBorderWidth, fill);
  }
}

/// Range-slider custom thumb shape — same visual as [_BTThumbShape].
class _BTRangeThumbShape extends RangeSliderThumbShape {
  const _BTRangeThumbShape({required this.borderColor});

  final Color borderColor;

  @override
  Size getPreferredSize(bool isEnabled, bool isDiscrete) =>
      const Size.fromRadius(_kThumbRadius);

  @override
  void paint(
    PaintingContext context,
    Offset center, {
    required Animation<double> activationAnimation,
    required Animation<double> enableAnimation,
    required SliderThemeData sliderTheme,
    bool isDiscrete = false,
    bool isEnabled = true,
    bool isOnTop = false,
    TextDirection textDirection = TextDirection.ltr,
    Thumb thumb = Thumb.start,
    bool isPressed = false,
  }) {
    final canvas = context.canvas;
    final fill = Paint()
      ..color = sliderTheme.thumbColor ?? const Color(0xFF000000);

    canvas
      ..drawCircle(center, _kThumbRadius, Paint()..color = borderColor)
      ..drawCircle(center, _kThumbRadius - _kBorderWidth, fill);
  }
}

// ── Custom tooltip (value indicator) — Figma 434:7544 ──────────────────

// Dark pill: bg.inverse (theme-driven) + radius.sm + 16×8 dp downward arrow.
const _kTooltipPaddingH = 12.0; // spacing.md
const _kTooltipPaddingV = 8.0; // spacing.sm
const _kTooltipRadius = 8.0; // radius.sm
const _kArrowHalfWidth = 8.0; // half of 16 dp total
const _kArrowHeight = 8.0; // arrow height
const _kArrowGap = 2.0; // gap: arrow tip → thumb top

/// Shared painter: dark rounded pill + 16×8 dp downward arrow.
///
/// Scales from the arrow-tip pivot (thumb top − [_kArrowGap]) so the
/// tooltip pops in smoothly as [scale] goes 0 → 1.
void _paintBTTooltip(
  Canvas canvas,
  Offset center, {
  required TextPainter labelPainter,
  required double scale,
  required Color bgColor,
}) {
  final textW = labelPainter.width;
  final textH = labelPainter.height;
  final pillW = textW + _kTooltipPaddingH * 2;
  final pillH = textH + _kTooltipPaddingV * 2;

  // Arrow tip: 2 dp above thumb top edge
  final pivotDy = center.dy - _kThumbRadius - _kArrowGap;
  final arrowBase = pivotDy - _kArrowHeight;
  final pillTop = arrowBase - pillH;
  final pillLeft = center.dx - pillW / 2;

  final paint = Paint()..color = bgColor;
  final pillRect = RRect.fromLTRBR(
    pillLeft,
    pillTop,
    pillLeft + pillW,
    arrowBase,
    const Radius.circular(_kTooltipRadius),
  );
  final arrowPath = Path()
    ..moveTo(center.dx - _kArrowHalfWidth, arrowBase)
    ..lineTo(center.dx + _kArrowHalfWidth, arrowBase)
    ..lineTo(center.dx, pivotDy)
    ..close();

  // Scale animation from arrow-tip pivot; all shape ops in one cascade.
  canvas
    ..save()
    ..translate(center.dx, pivotDy)
    ..scale(scale, scale)
    ..translate(-center.dx, -pivotDy)
    ..drawRRect(pillRect, paint)
    ..drawPath(arrowPath, paint);

  // labelPainter.paint is on a different receiver — cascade resumes after.
  labelPainter.paint(
    canvas,
    Offset(center.dx - textW / 2, pillTop + _kTooltipPaddingV),
  );

  canvas.restore();
}

/// Single-thumb value indicator: dark pill + 16×8 dp downward arrow.
class _BTValueIndicatorShape extends SliderComponentShape {
  const _BTValueIndicatorShape({required this.bgColor});

  final Color bgColor;

  @override
  Size getPreferredSize(
    bool isEnabled,
    bool isDiscrete, {
    TextPainter? labelPainter,
    double? textScaleFactor,
  }) {
    final w = (labelPainter?.width ?? 0) + _kTooltipPaddingH * 2;
    final h = (labelPainter?.height ?? 0) +
        _kTooltipPaddingV * 2 +
        _kArrowHeight +
        _kArrowGap;
    return Size(w, h);
  }

  @override
  void paint(
    PaintingContext context,
    Offset center, {
    required Animation<double> activationAnimation,
    required Animation<double> enableAnimation,
    required bool isDiscrete,
    required TextPainter labelPainter,
    required RenderBox parentBox,
    required SliderThemeData sliderTheme,
    required TextDirection textDirection,
    required double value,
    required double textScaleFactor,
    required Size sizeWithOverflow,
  }) {
    final scale = activationAnimation.value;
    if (scale == 0.0) return;
    _paintBTTooltip(
      context.canvas,
      center,
      labelPainter: labelPainter,
      scale: scale,
      bgColor: bgColor,
    );
  }
}

/// Range value indicator — same visual as [_BTValueIndicatorShape].
///
/// Flutter drives BOTH thumbs' indicators with the same activation animation,
/// so without [activeThumb] gating, dragging one thumb pops the *other*
/// thumb's tooltip too. We only paint the tooltip for the thumb currently
/// being dragged ([activeThumb]); when nothing is dragged we paint neither.
class _BTRangeValueIndicatorShape extends RangeSliderValueIndicatorShape {
  const _BTRangeValueIndicatorShape({required this.bgColor, this.activeThumb});

  final Color bgColor;
  final Thumb? activeThumb;

  @override
  Size getPreferredSize(
    bool isEnabled,
    bool isDiscrete, {
    required TextPainter labelPainter,
    required double textScaleFactor,
  }) {
    final w = labelPainter.width + _kTooltipPaddingH * 2;
    final h = labelPainter.height +
        _kTooltipPaddingV * 2 +
        _kArrowHeight +
        _kArrowGap;
    return Size(w, h);
  }

  @override
  void paint(
    PaintingContext context,
    Offset center, {
    required Animation<double> activationAnimation,
    required Animation<double> enableAnimation,
    required TextPainter labelPainter,
    required RenderBox parentBox,
    required SliderThemeData sliderTheme,
    bool isDiscrete = false,
    bool isOnTop = false,
    TextDirection textDirection = TextDirection.ltr,
    double textScaleFactor = 1,
    Size sizeWithOverflow = Size.zero,
    Thumb thumb = Thumb.start,
    double value = 0,
    double? openIndicatorOffset,
  }) {
    final scale = activationAnimation.value;
    if (scale == 0.0) return;
    // Only the dragged thumb shows its tooltip. `activeThumb == null` (idle /
    // static press) paints neither — and crucially keeps the *other* thumb
    // hidden while the indicator fades out after release.
    if (thumb != activeThumb) return;
    _paintBTTooltip(
      context.canvas,
      center,
      labelPainter: labelPainter,
      scale: scale,
      bgColor: bgColor,
    );
  }
}

// ── Widget ───────────────────────────────────────────────────────────────

class BTSlider extends StatefulWidget {
  /// Horizontal slider with a single thumb.
  const BTSlider({
    this.value,
    this.min = 0,
    this.max = 100,
    this.divisions,
    this.showTooltip = true,
    this.alwaysShown = true,
    this.disabled = false,
    this.variant = BTSliderVariant.defaults,
    this.onValueChanged,
    super.key,
  })  : type = BTSliderType.defaults,
        startValue = null,
        endValue = null,
        onStartChanged = null,
        onEndChanged = null;

  /// Horizontal slider with two thumbs (start + end).
  const BTSlider.range({
    this.startValue,
    this.endValue,
    this.min = 0,
    this.max = 100,
    this.divisions,
    this.showTooltip = true,
    this.alwaysShown = true,
    this.disabled = false,
    this.variant = BTSliderVariant.defaults,
    this.onStartChanged,
    this.onEndChanged,
    super.key,
  })  : type = BTSliderType.range,
        value = null,
        onValueChanged = null;

  /// Vertical slider with a single thumb.
  const BTSlider.vertical({
    this.value,
    this.min = 0,
    this.max = 100,
    this.divisions,
    this.showTooltip = true,
    this.alwaysShown = true,
    this.disabled = false,
    this.variant = BTSliderVariant.defaults,
    this.onValueChanged,
    super.key,
  })  : type = BTSliderType.vertical,
        startValue = null,
        endValue = null,
        onStartChanged = null,
        onEndChanged = null;

  final BTSliderType type;
  final BTSliderVariant variant;

  final double? value;
  final double? startValue;
  final double? endValue;

  final double min;
  final double max;
  final int? divisions;
  final bool showTooltip;

  /// When `true` (default) the tooltip is always visible.
  /// When `false` the tooltip only shows while the user is interacting.
  final bool alwaysShown;

  /// Disables all interaction. @default false
  final bool disabled;

  final ValueChanged<double>? onValueChanged;
  final ValueChanged<double>? onStartChanged;
  final ValueChanged<double>? onEndChanged;

  @override
  State<BTSlider> createState() => _BTSliderState();
}

class _BTSliderState extends State<BTSlider> {
  late double _value;
  late double _start;
  late double _end;
  /// Which range thumb is being dragged — drives single-tooltip behaviour.
  Thumb? _activeThumb;

  @override
  void initState() {
    super.initState();
    _value = widget.value ?? (widget.min + widget.max) / 2;
    _start = widget.startValue ?? widget.min + (widget.max - widget.min) * 0.2;
    _end = widget.endValue ?? widget.max - (widget.max - widget.min) * 0.2;
  }

  @override
  void didUpdateWidget(covariant BTSlider old) {
    super.didUpdateWidget(old);
    if (widget.value != null) _value = widget.value!;
    if (widget.startValue != null) _start = widget.startValue!;
    if (widget.endValue != null) _end = widget.endValue!;
  }

  double get _currentValue => widget.value ?? _value;
  double get _currentStart => widget.startValue ?? _start;
  double get _currentEnd => widget.endValue ?? _end;

  Color _activeColor(BuildContext context) => switch (widget.variant) {
        BTSliderVariant.defaults => context.btColor.icon.primary,
        BTSliderVariant.error => context.btColor.icon.error,
      };

  Color _thumbColor(BuildContext context) => switch (widget.variant) {
    BTSliderVariant.defaults => context.btColor.icon.inverse,
    BTSliderVariant.error    => context.btColor.icon.error,
  };

  SliderThemeData _theme(BuildContext context, Color active) {
    final inactive = active.withValues(alpha: 0.25);
    final c = context.btColor;
    final borderColor = c.border.primary;
    return SliderTheme.of(context).copyWith(
      activeTrackColor: active,
      inactiveTrackColor: inactive,
      thumbColor: _thumbColor(context),
      // Hover / press halo around thumb — Figma 434:7227.
      // Flutter renders the overlay automatically during hover / press / focus;
      // a single static color is enough (cannot use WidgetStateProperty here —
      // SliderThemeData.overlayColor is Color? in this SDK).
      // Text style for the custom value-indicator labelPainter — text.inverse
      // (white in light mode, dark in dark mode — opposite of bg.inverse).
      valueIndicatorTextStyle: TextStyle(
        color: c.text.inverse,
        fontSize: 14,
        fontWeight: FontWeight.w500,
      ),
      showValueIndicator: widget.alwaysShown
          ? ShowValueIndicator.always
          : ShowValueIndicator.onlyForContinuous,
      trackHeight: 4,
      overlayShape: const RoundSliderOverlayShape(overlayRadius: 18),
      thumbShape: _BTThumbShape(borderColor: borderColor),
      valueIndicatorShape: _BTValueIndicatorShape(bgColor: c.bg.inverse),
    );
  }

  @override
  Widget build(BuildContext context) {
    final active = _activeColor(context);
    final sliderTh = _theme(context, active);

    if (widget.type == BTSliderType.range) {
      return SliderTheme(
        data: sliderTh.copyWith(
          rangeThumbShape:
              _BTRangeThumbShape(borderColor: context.btColor.border.primary),
          rangeValueIndicatorShape: _BTRangeValueIndicatorShape(
            bgColor: context.btColor.bg.inverse,
            activeThumb: _activeThumb,
          ),
        ),
        child: RangeSlider(
          values: RangeValues(_currentStart, _currentEnd),
          min: widget.min,
          max: widget.max,
          divisions: widget.divisions,
          overlayColor: WidgetStateProperty.all(
            context.btColor.icon.primary.withValues(alpha: 0.5),
          ),
          labels: widget.showTooltip
              ? RangeLabels(
                  _currentStart.toStringAsFixed(0),
                  _currentEnd.toStringAsFixed(0),
                )
              : null,
          // Clear on press so the static-press moment shows no tooltip and a
          // new grab never flashes the previously-dragged thumb. The active
          // thumb is resolved on the first move below. We deliberately do NOT
          // clear on release — keeping it lets the indicator fade out for the
          // correct thumb only (no end/start flash) and avoids an extra
          // rebuild during the overlay fade.
          onChangeStart: widget.disabled
              ? null
              : (_) => setState(() => _activeThumb = null),
          onChanged: widget.disabled
              ? null
              : (RangeValues v) {
                  setState(() {
                    // Resolve active thumb from whichever value actually moved.
                    if (v.start != _start) {
                      _activeThumb = Thumb.start;
                    } else if (v.end != _end) {
                      _activeThumb = Thumb.end;
                    }
                    _start = v.start;
                    _end = v.end;
                  });
                  widget.onStartChanged?.call(v.start);
                  widget.onEndChanged?.call(v.end);
                },
        ),
      );
    }

    final slider = SliderTheme(
      data: sliderTh,
      child: Slider(
        value: _currentValue,
        min: widget.min,
        max: widget.max,
        divisions: widget.divisions,
        label: widget.showTooltip ? _currentValue.toStringAsFixed(0) : null,
        overlayColor: WidgetStateProperty.all(
          context.btColor.icon.primary.withValues(alpha: 0.5),
        ),
        onChanged: widget.disabled
            ? null
            : (double v) {
                setState(() => _value = v);
                widget.onValueChanged?.call(v);
              },
      ),
    );

    if (widget.type == BTSliderType.vertical) {
      return RotatedBox(
        quarterTurns: -1, // 90° counter-clockwise → bottom=0, top=max
        child: slider,
      );
    }

    return slider;
  }
}
